// Rich panel: Step Sequencer — step grid generated by the real tool. Now also exposes
// randomize_pattern (real note mutation) and set_step_param (velocity, undoable) — both existed
// in the backend but had no UI.
window.LiveStudioPanels = window.LiveStudioPanels || {};
window.LiveStudioPanels.stepseq = function (panel, helpers) {
  const exec = helpers.execute;
  const api = helpers.api;
  panel.innerHTML = `
    <div class="panel-head"><h1>🔢 Step Sequencer</h1><p>Generate a pattern and edit the steps. Each cell calls the real tool.</p></div>
    <div class="ss-toolbar">
      <label class="hint">Steps</label>
      <select id="ss-steps"><option>8</option><option selected>16</option><option>32</option></select>
      <button class="btn" id="ss-gen">Generate pattern</button>
      <span class="hint" id="ss-info"></span>
    </div>
    <div id="ss-grid" class="ss-grid"><span class="hint">Click "Generate pattern".</span></div>
    <div class="ss-toolbar" style="margin-top:12px">
      <label class="hint">Density</label><input id="ss-density" type="range" min="0" max="100" value="50" style="width:100px" />
      <label class="hint">Variation</label><input id="ss-variation" type="range" min="0" max="100" value="50" style="width:100px" />
      <button class="btn ghost" id="ss-random">Randomize</button>
      <span class="hint">Selected step:</span><span class="hint" id="ss-selstep">none — click a lit step</span>
      <label class="hint">Velocity</label><input id="ss-vel" type="range" min="1" max="127" value="100" style="width:100px" />
      <button class="btn ghost" id="ss-setvel">Set velocity</button>
    </div>`;

  let trackIndex = 0, clipIndex = 0, selectedStep = null;

  async function refreshFromClip() {
    const r = await api.post("/api/execute", { name: "notation__get_clip_notes", args: { track_index: trackIndex, clip_index: clipIndex } });
    if (!r.success) return;
    const g = 0.25;
    const steps = Array.from({ length: 16 }, (_, i) => {
      const n = r.data.notes.find((n) => Math.abs(n.start - i * g) < g / 2);
      return { step: i, active: !!n, velocity: n ? n.velocity : 100 };
    });
    render(steps);
  }
  async function gen() {
    const steps = Number(panel.querySelector("#ss-steps").value);
    const r = await exec("set_pattern", { track_index: 0, steps });
    if (!r.success) { panel.querySelector("#ss-grid").innerHTML = `<span class="hint">${r.error}</span>`; return; }
    trackIndex = r.data.trackIndex; clipIndex = r.data.clipIndex;
    panel.querySelector("#ss-info").textContent = `${r.data.activeSteps}/${r.data.totalSteps} active · ${r.data.resolution}`;
    render(r.data.steps);
  }
  function render(steps) {
    const grid = panel.querySelector("#ss-grid");
    grid.innerHTML = "";
    grid.style.gridTemplateColumns = `repeat(${Math.min(steps.length,16)}, 1fr)`;
    steps.forEach((s) => {
      const cell = document.createElement("div");
      cell.className = "ss-cell" + (s.active ? " on" : "") + (selectedStep === s.step ? " sel" : "");
      cell.title = `step ${s.step+1} · vel ${s.velocity}`;
      if (s.active) cell.style.opacity = (0.4 + (s.velocity/127)*0.6).toFixed(2);
      cell.onclick = async () => {
        const r = await exec("toggle_step", { track_index: trackIndex, clip_index: clipIndex, step: s.step });
        s.active = r.data?.nowActive;
        cell.classList.toggle("on", s.active);
        cell.style.opacity = s.active ? "1" : "";
        if (s.active) { selectedStep = s.step; panel.querySelector("#ss-selstep").textContent = `step ${s.step + 1}`; }
      };
      grid.appendChild(cell);
    });
  }
  panel.querySelector("#ss-gen").onclick = gen;
  panel.querySelector("#ss-random").onclick = async () => {
    const density = Number(panel.querySelector("#ss-density").value), variation = Number(panel.querySelector("#ss-variation").value);
    const r = await exec("randomize_pattern", { track_index: trackIndex, clip_index: clipIndex, density, variation });
    if (r.success) { panel.querySelector("#ss-info").textContent = `Randomized: ${r.data.activeSteps} active (${r.data.density}% density)`; refreshFromClip(); }
    else panel.querySelector("#ss-info").textContent = r.error;
  };
  panel.querySelector("#ss-setvel").onclick = async () => {
    if (selectedStep == null) { panel.querySelector("#ss-info").textContent = "Click a lit step first."; return; }
    const value = Number(panel.querySelector("#ss-vel").value);
    const r = await exec("set_step_param", { track_index: trackIndex, clip_index: clipIndex, step: selectedStep, param: "velocity", value });
    if (r.success) refreshFromClip(); else panel.querySelector("#ss-info").textContent = r.error;
  };
  gen();
};
